from sentence_transformers import SentenceTransformer, util

class HomieQA:
    def __init__(self, chunks):
        self.model = SentenceTransformer("all-MiniLM-L6-v2")
        self.chunks = chunks
        self.emb = self.model.encode(
            chunks, normalize_embeddings=True, convert_to_tensor=True
        )

    def answer(self, question, threshold=0.45):
        q = self.model.encode(
            question, normalize_embeddings=True, convert_to_tensor=True
        )
        scores = util.cos_sim(q, self.emb)[0]
        best = int(scores.argmax())
        if float(scores[best]) < threshold:
            return "I don't have enough context to answer that."
        return self.chunks[best]

bot = HomieQA(["Click 'Forgot password' to recover access.", "We are open 9 to 5."])
print(bot.answer("how do I reset my login?"))
print(bot.answer("what is the meaning of life?"))

